  const [fullRestoreSimResult, setFullRestoreSimResult] = useState(null);
  // { logId, result, skippedTenants, totalOps, totalBatches, opsByArea, beforeBackupFileName, logSnapshot }

  // ★ Phase G1 本番 災害復旧復元（全体上書き）用 state
